+      deviceRaw: { id: "dev-2", publicKey: "pk", signature: "sig", signedAt: Date.now() },
+    });
+    expect(regular.allowBypass).toBe(false);
+    expect(regular.device?.id).toBe("dev-2");
+  });
+
+  test("evaluates missing-device decisions", () => {
