+    ).toBe("reject-control-ui-insecure-auth");
+
+    expect(
+      evaluateMissingDeviceIdentity({
+        hasDeviceIdentity: false,
+        role: "operator",
+        isControlUi: false,
+        controlUiAuthPolicy: policy,
+        sharedAuthOk: true,
+        authOk: true,
+        hasSharedAuth: true,
+      }).kind,
+    ).toBe("allow");
+
+    expect(
+      evaluateMissingDeviceIdentity({
+        hasDeviceIdentity: false,
+        role: "operator",
+        isControlUi: false,
+        controlUiAuthPolicy: policy,
+        sharedAuthOk: false,
+        authOk: false,
+        hasSharedAuth: true,
+      }).kind,
+    ).toBe("reject-unauthorized");
+
+    expect(
+      evaluateMissingDeviceIdentity({
+        hasDeviceIdentity: false,
+        role: "node",
+        isControlUi: false,
